using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
            // Preserve the old name so existing 500K documents and direct SQL queries still work.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed the id format from "EntityType|Key" to just "Key".
            // Use IdProperty() with value generation to keep reading old "Product|123" ids.
            entity.Property(p => p.Id)
                  .HasConversion<string>()
                  .ToJsonProperty("id");
            entity.HasPartitionKey(p => p.Id);
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Opt out of the simplified id format so new writes also use "Product|123".
        configurationBuilder.Conventions.Remove(
            typeof(Microsoft.EntityFrameworkCore.Cosmos.Metadata.Conventions.CosmosNoDiscriminatorInIdConvention));
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

